// BAD: moment.js is 300KB+ and not tree-shakeable
import moment from "moment";

function formatDate(date: string): string {
  return moment(date).format("MMM D, YYYY");
}

// BAD: importing the entire lodash library for one function
import _ from "lodash";

function getUnique(items: string[]): string[] {
  return _.uniq(items);
}

// GOOD: date-fns is tree-shakeable -- only the format function is bundled
import { format } from "date-fns";

function formatDate(date: string): string {
  return format(new Date(date), "MMM d, yyyy");
}

// GOOD: import only the specific lodash function (3KB vs 70KB)
import uniq from "lodash/uniq";

function getUnique(items: string[]): string[] {
  return uniq(items);
}

// GOOD: dynamic import for a heavy component only loaded when needed
const PdfViewer = lazy(() => import("./PdfViewer"));

function DocumentPage() {
  return (
    <Suspense fallback={<Spinner />}>
      <PdfViewer />
    </Suspense>
  );
}
